        void CurPropTag_DrawItem(object sender, System.Windows.Forms.DrawItemEventArgs e)
        {
            // If the index is invalid then simply exit.
            if (e.Index == -1 || e.Index >= CurPropTag.Items.Count)
                return;
            // Draw the background of the item.
            e.DrawBackground();

            // Should we draw the focus rectangle?
            if ((e.State & System.Windows.Forms.DrawItemState.Focus) != 0)
                e.DrawFocusRectangle();

            System.Drawing.Brush b = null;
            try
            {
                b = new System.Drawing.SolidBrush(e.ForeColor);
                if (CurPropTag.Items[e.Index].ToString().StartsWith("[C]"))
                {
                    // Create a new background brush.
                    //b = new System.Drawing.TextureBrush();

                    e.Graphics.DrawImage(FTDPClient.controls.controls.GetIconByPartID(((FTDPClient.forms.imageComboBoxItem)(CurPropTag.Items[e.Index])).ImageIndex), new System.Drawing.RectangleF(e.Bounds.X, e.Bounds.Y + (e.Bounds.Height - 15) / 2, 15, 15));
                    // Draw the item.

                    e.Graphics.DrawString(
                        CurPropTag.Items[e.Index].ToString().Substring(3),
                        e.Font,
                        b,
                        new System.Drawing.RectangleF(e.Bounds.X + 16, e.Bounds.Y+2, e.Bounds.Width - 16, e.Bounds.Height)
                        );
                }
                else
                {
                    e.Graphics.DrawString(
                        CurPropTag.Items[e.Index].ToString(),
                        e.Font,
                        b,
                        new System.Drawing.RectangleF(e.Bounds.X, e.Bounds.Y+2, e.Bounds.Width, e.Bounds.Height)
                        );
                }
            } // End try

            finally
            {

                // Should we cleanup the brush?
                if (b != null)
                    b.Dispose();

                b = null;

            } // End finally
        }

